module RefModule(
    input [15:0] num,
    output reg [3:0] ones_count // Change output to reg type
);integer i;
reg [15:0] final_sig;

always @(*) begin
    ones_count = 0;
    final_sig = num;
    for (i = 0; i < 16; i = i + 1) begin
        ones_count = ones_count + final_sig[0];
        final_sig = final_sig >> 1;
    end
end

endmodule
